    if (cur.outline_color.x != base.outline_color.x || cur.outline_color.y != base.outline_color.y || cur.outline_color.z != base.outline_color.z) flags = flags | post_process_DeltaFlags::f_outline_color;
    if (cur.outline_thickness != base.outline_thickness) flags = flags | post_process_DeltaFlags::f_outline_thickness;
    if (cur.outline_depth_threshold != base.outline_depth_threshold) flags = flags | post_process_DeltaFlags::f_outline_depth_threshold;
